/**
 * The Void — Item Catalog & Drop System
 *
 * Every item in The Void is:
 * 1. Math-based rarity (drop probability = 1/β₁)
 * 2. ZK proof-of-work verified (the item formalizes the proof you were there)
 * 3. Dimension-locked (can only drop in its native dimension)
 * 4. God Formula governed (item effects modify R, v, or w)
 *
 * This is the money maker. Natural value emerges from mathematical
 * improbability. Buyers on Nexus can verify the work was real.
 *
 * @module @a0n/gnosis/void-item-catalog
 */

import type {
  DimensionIndex,
  GnosticDimensionIndex,
  RarityTier,
  GameCoordinate,
  PhyleName,
  ParticleType,
  CosmicFeature,
} from './void-game-types';

import { GNOSTIC } from './math';

// ── Item Categories ─────────────────────────────────────────────────

export type ItemCategory =
  | 'weapon'       // Modify encounter success rate
  | 'armor'        // Reduce HEX cost per action
  | 'consumable'   // One-time use effects
  | 'material'     // Crafting ingredients — DROP THESE
  | 'relic'        // Permanent passive effects (extremely rare)
  | 'cosmetic'     // Visual only (still rare, still valuable)
  | 'key'          // Opens specific dimensional gates
  | 'blueprint';   // Unlocks crafting recipes

export type ItemSlot =
  | 'mainhand'
  | 'offhand'
  | 'helm'
  | 'chest'
  | 'legs'
  | 'boots'
  | 'trinket_1'
  | 'trinket_2'
  | 'none';        // Consumables, materials, blueprints

export type ParticleTypeAffinity =
  | ParticleType
  | 'dps'
  | 'tank'
  | 'fixer'
  | 'range'
  | 'healer';

// ── God Formula Item Effects ────────────────────────────────────────

/**
 * Item effects are expressed as God Formula modifiers.
 * They modify the player's R (budget), v (cost), or w (weight).
 * This keeps balance formally provable.
 */
export interface GodFormulaModifier {
  /** Flat bonus to R (effective HEX pool for encounter resolution) */
  readonly rBonus: number;
  /** Multiplier on encounter difficulty v (< 1 = easier encounters) */
  readonly vMultiplier: number;
  /** Bonus to w (direct weight bonus, stacks additively) */
  readonly wBonus: number;
  /** Reduction to movement HEX cost (additive, min cost remains 1) */
  readonly moveCostReduction: number;
  /** Bonus learning energy per failure */
  readonly learningBonus: number;
  /** Stagnation drain resistance (multiplier, < 1 = slower drain) */
  readonly drainResistance: number;
}

/** No-op modifier — the identity element */
export const IDENTITY_MODIFIER: GodFormulaModifier = {
  rBonus: 0,
  vMultiplier: 1,
  wBonus: 0,
  moveCostReduction: 0,
  learningBonus: 0,
  drainResistance: 1,
} as const;

// ── Item Definition ─────────────────────────────────────────────────

export interface VoidItem {
  /** Unique item template ID */
  readonly itemId: string;
  readonly name: string;
  readonly description: string;
  readonly category: ItemCategory;
  readonly slot: ItemSlot;
  /** Native dimension — can only drop in this dimension */
  readonly nativeDimension: DimensionIndex;
  readonly rarity: RarityTier;
  /** God Formula modifier when equipped */
  readonly modifier: GodFormulaModifier;
  /** Phyle affinity — bonus when used by this phyle */
  readonly phyleAffinity: PhyleName | null;
  /** Archetype affinity — bonus when used by this particleType */
  readonly particleTypeAffinity: ParticleTypeAffinity | null;
  /** Stack size (1 = unique, >1 = stackable materials/consumables) */
  readonly maxStack: number;
  /** Whether this item is tradeable on Nexus */
  readonly tradeable: boolean;
  /** If true, consumed on use */
  readonly consumeOnUse: boolean;
}

// ── Drop Table System ───────────────────────────────────────────────

/**
 * A single entry in a drop table.
 *
 * Drop tables are per-dimension, per-encounter-type.
 * The weight system uses the God Formula:
 *   dropWeight = baseWeight / β₁(dimension)
 *
 * This means:
 * - Common items from Proton (β₁=3): weight/3
 * - Rare items from Void (β₁=21): weight/21
 * - Cosmic items from Pleroma (β₁=55): weight/55
 *
 * The math formalizes the rarity. No arbitrary percentages.
 */
export interface DropTableEntry {
  readonly itemId: string;
  /** Base weight before dimension scaling. Higher = more common within tier. */
  readonly baseWeight: number;
  /** Minimum number of this item to drop */
  readonly minQuantity: number;
  /** Maximum number of this item to drop */
  readonly maxQuantity: number;
  /** Additional condition: require specific cosmic feature on tile */
  readonly requiresFeature?: CosmicFeature;
  /** Additional condition: require minimum failures */
  readonly requiresMinFailures?: number;
  /** Additional condition: require specific phyle */
  readonly requiresPhyle?: PhyleName;
}

export interface DimensionDropTable {
  /** Dimension this table applies to */
  readonly dimension: DimensionIndex;
  /** Common drops (always check) */
  readonly common: readonly DropTableEntry[];
  /** Uncommon drops (check on encounter resolution) */
  readonly uncommon: readonly DropTableEntry[];
  /** Rare drops (check only on failure — failure finds the good stuff) */
  readonly rare: readonly DropTableEntry[];
  /** Boss drop (guaranteed on boss encounter kill) */
  readonly boss: readonly DropTableEntry[];
  /** Secret drops (require specific conditions — discoverable, not documented) */
  readonly secret: readonly DropTableEntry[];
}

