// ── Master Catalog ──────────────────────────────────────────────────

/** All items in the game, indexed by itemId */
export const ITEM_CATALOG: ReadonlyMap<string, VoidItem> = new Map(
  [
    ...BYTHOS_ITEMS,
    ...BARBELO_ITEMS,
    ...SYZYGY_ITEMS,
    ...PROTON_ITEMS,
    ...EMANATIONS_ITEMS,
    ...SOPHIA_ITEMS,
    ...VOID_ITEMS,
    ...PLEROMA_ITEMS,
    ...BOSS_ITEMS,
  ].map((item) => [item.itemId, item])
);

/** Get all items for a specific dimension */
export function getItemsForDimension(dim: DimensionIndex): VoidItem[] {
  return [...ITEM_CATALOG.values()].filter(
    (item) => item.nativeDimension === dim
  );
}

// ── Drop Tables ─────────────────────────────────────────────────────

/**
 * The β₁-indexed drop table system.
 *
 * Every dimension has its own drop table. Drop probability for each
 * item = (baseWeight / totalWeight) × (1/β₁).
 *
 * This means a Cosmic item from Pleroma (β₁=55) with baseWeight 1 and
 * totalWeight 100 has probability: (1/100) × (1/55) = 1/5500.
 *
 * That's provably rare. And ZK-verified. And tradeable on Nexus.
 */
