// ── Drop Resolution ─────────────────────────────────────────────────

export interface ResolvedDrop {
  readonly item: VoidItem;
  readonly quantity: number;
  /** Mathematical improbability of this drop (for display/trading) */
  readonly improbability: number;
}

/**
 * Resolve drops from a dimension's drop table.
 *
 * The math:
 * 1. Select applicable tier (common/uncommon/rare based on outcome)
 * 2. For each entry in the tier: probability = baseWeight/totalWeight × 1/β₁
 * 3. Roll against each entry independently
 * 4. Failed encounters check the RARE table (failure finds the good stuff)
 *
 * @param dimension - Current dimension
 * @param beta1 - β₁ value of this dimension
 * @param isFailure - Whether the encounter was a failure (checks rare table)
 * @param isBoss - Whether this was a boss encounter (checks boss table)
 * @param rng - Seeded PRNG function returning [0, 1)
 * @param playerFailures - Player's total failures (for secret drops)
 * @param tileFeature - Cosmic feature on this tile (for conditional drops)
 * @param playerPhyle - Player's major phyle (for phyle-locked drops)
 */
export function resolveDrops(
  dimension: DimensionIndex,
  beta1: number,
  isFailure: boolean,
  isBoss: boolean,
  rng: () => number,
  playerFailures: number,
  tileFeature: CosmicFeature = 'none',
  playerPhyle?: PhyleName
): ResolvedDrop[] {
  const table = DIMENSION_DROP_TABLES.get(dimension);
  if (!table) return [];
  if (beta1 === 0) beta1 = 1; // Bythos fallback

  const drops: ResolvedDrop[] = [];

  // Always check common
  checkTable(table.common, beta1, rng, drops, playerFailures, tileFeature, playerPhyle);

  // Check uncommon on any encounter
  checkTable(table.uncommon, beta1, rng, drops, playerFailures, tileFeature, playerPhyle);

  // Failure unlocks the RARE table — failure finds the good stuff
  if (isFailure) {
    checkTable(table.rare, beta1, rng, drops, playerFailures, tileFeature, playerPhyle);
    // Secret drops also checked on failure
    checkTable(table.secret, beta1, rng, drops, playerFailures, tileFeature, playerPhyle);
  }

  // Boss: guaranteed drop from boss table
  if (isBoss && table.boss.length > 0) {
    const bossEntry = table.boss[Math.floor(rng() * table.boss.length)];
    if (bossEntry) {
      const item = ITEM_CATALOG.get(bossEntry.itemId);
      if (item) {
        const qty = bossEntry.minQuantity +
          Math.floor(rng() * (bossEntry.maxQuantity - bossEntry.minQuantity + 1));
        drops.push({
          item,
          quantity: qty,
          improbability: beta1 * beta1, // Boss drops: β₁² improbability
        });
      }
    }
  }

  return drops;
}

/** Check a tier's drop table entries against the RNG */
function checkTable(
  entries: readonly DropTableEntry[],
  beta1: number,
  rng: () => number,
  drops: ResolvedDrop[],
  playerFailures: number,
  tileFeature: CosmicFeature,
  playerPhyle?: PhyleName
): void {
  const totalWeight = entries.reduce((sum, e) => sum + e.baseWeight, 0);
  if (totalWeight === 0) return;

  for (const entry of entries) {
    // Check conditions
    if (entry.requiresFeature && entry.requiresFeature !== tileFeature) continue;
    if (entry.requiresMinFailures && playerFailures < entry.requiresMinFailures) continue;
    if (entry.requiresPhyle && entry.requiresPhyle !== playerPhyle) continue;

    // Drop probability = (baseWeight / totalWeight) × (1 / β₁)
    const probability = (entry.baseWeight / totalWeight) / beta1;
    const roll = rng();

    if (roll < probability) {
      const item = ITEM_CATALOG.get(entry.itemId);
      if (item) {
        const qty = entry.minQuantity +
          Math.floor(rng() * (entry.maxQuantity - entry.minQuantity + 1));
        drops.push({
          item,
          quantity: qty,
          improbability: 1 / probability, // How rare this drop is
        });
      }
    }
  }
}

// ── Inventory System ────────────────────────────────────────────────

/** Maximum inventory slots */
export const MAX_INVENTORY_SLOTS = 40;

export interface InventorySlot {
  readonly itemId: string;
  quantity: number;
}

export interface observerEquipment {
  mainhand: VoidItem | null;
  offhand: VoidItem | null;
  helm: VoidItem | null;
  chest: VoidItem | null;
  legs: VoidItem | null;
  boots: VoidItem | null;
  trinket_1: VoidItem | null;
  trinket_2: VoidItem | null;
}

export interface observerInventory {
  readonly slots: InventorySlot[];
  readonly equipment: observerEquipment;
}

/** Create empty inventory */
export function createEmptyInventory(): observerInventory {
  return {
    slots: [],
    equipment: {
      mainhand: null,
      offhand: null,
      helm: null,
      chest: null,
      legs: null,
      boots: null,
      trinket_1: null,
      trinket_2: null,
    },
  };
}

/**
 * Calculate the total God Formula modifier from all equipped items.
 * Modifiers stack additively (R bonus, w bonus, learning bonus)
 * and multiplicatively (v multiplier, drain resistance).
 */
export function calculateEquipmentModifier(
  equipment: observerEquipment
): GodFormulaModifier {
  const equipped = Object.values(equipment).filter(
    (item): item is VoidItem => item !== null
  );

  let rBonus = 0;
  let vMultiplier = 1;
  let wBonus = 0;
  let moveCostReduction = 0;
  let learningBonus = 0;
  let drainResistance = 1;

  for (const item of equipped) {
    rBonus += item.modifier.rBonus;
    vMultiplier *= item.modifier.vMultiplier;
    wBonus += item.modifier.wBonus;
    moveCostReduction = Math.min(0.9, moveCostReduction + item.modifier.moveCostReduction);
    learningBonus += item.modifier.learningBonus;
    drainResistance *= item.modifier.drainResistance;
  }

  return { rBonus, vMultiplier, wBonus, moveCostReduction, learningBonus, drainResistance };
}

/**
 * Calculate a drop's trade value in HEX on Nexus.
 *
 * Value = improbability × β₁_at_drop × (1 + modifier_power)
 *
 * The math determines the price. No arbitrary pricing.
 * The rarer the drop, the more valuable. The higher the dimension
 * it came from, the more valuable. The better the stats, the more valuable.
 */
export function calculateNexusValue(
  item: VoidItem,
  improbability: number,
  beta1AtDrop: number
): number {
  const modPower = item.modifier.rBonus +
    (1 - item.modifier.vMultiplier) * 100 +
    item.modifier.wBonus * 10 +
    item.modifier.moveCostReduction * 50 +
    item.modifier.learningBonus * 20 +
    (1 - item.modifier.drainResistance) * 100;

  return Math.floor(improbability * beta1AtDrop * (1 + modPower / 100));
}
